/// <reference types="vite/client" />

declare module '*&imagetools' {
  const src: string;
  export default src;
}

declare module '*?format=webp&w=1400' {
  const src: string;
  export default src;
}

declare module '*?format=webp&w=1400&quality=75' {
  const src: string;
  export default src;
}

declare module '*?w=96' {
  const src: string;
  export default src;
}

declare module '*?w=80' {
  const src: string;
  export default src;
}
